INSERT INTO `category` VALUES (1,'Строительство','stroitelstvo','','','','','/uploads/01_g-min1516012353.jpg','Реализация проектов известных российских и мировых архитекторов. Инновационные методы строительства.'),(2,'Ремонт','remont','','','','','/uploads/02_g-min1516011760.jpg','Интерьеры премиум-класса. Уникальные технологии и непревзойденное качества реализации.'),(3,'Реконструкция','rekonstrukcia','','','','','/uploads/03_g-min1516012602.jpg','Реализация сложных и неординарных проектов. Самые современные инженерные разработки.'),(4,'Каталог','catalog','','','','','','Каталог');
