INSERT INTO `designer` VALUES (1,'Евгения и Павел Богатырёвы','evgenia-i-pavel-bogatyrevy','.','Учредители дизайн-студии «Mobile Line Decor» Евгения и Павел Богатырёвы вот уже почти 20 лет занимаются комплектацией эксклюзивных интерьеров класса люкс. При работе придерживаются двух аксиом: «стройка должна быть в радость» и «нельзя идти на компромиссы при постройке своего дома». Избегать компромиссов в проектах помогает наличие в компании трех собственных производств — столярного, текстильного и карнизного.','/uploads/design_01-min1516013512.png','Дизайн-студия «MOBILE LINE DЕCOR»','г. Москва, ул. Маршала Соколовского, д. 5','+7 (495) 234-90-99','+7 (903) 798-68-15','','www.m-ld.ru',NULL,NULL,NULL,NULL,1,23),(2,'Дмитрий Быков','sergej-samojlov','. ','Руководитель архитектурного бюро «ДИА», член Московского архитектурного общества и Союза московских архитекторов Дмитрий Быков главным в своей работе считает творческий поиск. Ориентирами на этом пути служат понимание задачи и контакт с заказчиком, а результатом — новые архитектурные образы. Бюро «ДИА» — лауреат российских и международных архитектурных конкурсов, специализируется на частных и общественных интерьерах, малоэтажном строительстве. ','/uploads/design_02-min1516013880.png','Архитектурное бюро «ДИА»','Москва, Ленинский пр., д. 30, оф. 185','+7 (495) 923-59-19','+7 (495) 954-26-10','','www.dia-ab.ru',NULL,NULL,NULL,NULL,1,1),(7,'Жанна Кочурова','zanna-kocurova','.','В портфолио Жанны Кочуровой — более тридцати авторских работ. Это интерьеры квартир и домов VIP-класса в Москве и Подмосковье. Главный принцип в проектировании — простота, индивидуальность, стилевое единство. Жанна Кочурова стремиться создавать комфортное для заказчика и его семьи пространство, отражая одновременно индивидуальность каждого члена семьи. Образ будущего дома рождается в диалоге с хозяевами.','/uploads/design_07-min1516022307.png','Авторские работы','','+7 (916) 690-15-70','','jj-9@yandex.ru','',NULL,NULL,NULL,NULL,1,2),(3,'Вера Герасимова','vera-gerasimova','. \r\n','Руководитель бюро, член Союза Дизайнеров России Вера Герасимова является автором всех выпускаемых студией проектов. Её творческое кредо: «Относиться к каждому проекту как к единственному». Специализация бюро — проектирование индивидуальных жилых домов и дизайн интерьеров. Работы «АРНАТ» становились лауреатами конкурсов INTERIA AWARDS, «Ландшафтная архитектура. Взгляд из дома», PINWIN. \r\n','/uploads/design_03-min1516014558.png','Архитектурно-дизайнерское бюро  «Арнат»','Москва, ул. Маршала Соколовского, д. 5','+7 (495) 225-70-48','','','www.arnat-design.ru ',NULL,NULL,NULL,NULL,1,3),(4,'Ирина Мавродиева  и Артур Гога','irina-mavrodieva-i-artur-goga','. \r\n','Ирина Мавродиева и Артур Гога создали свое бюро в 2004 году. Индивидуальный подход, уникальность и качество решений — основные принципы их работы. Бюро AMG-project — участник многочисленных выставок и конкурсов, в том числе, лауреат Interia Awards, архитектурной премии Союза архитекторов России, Московской биеннале архитектуры, фестиваля «Зодчество», «Под крышей Дома». Работы бюро опубликованы в российской и зарубежной прессе. \r\n','/uploads/design_04-min1516015357.png','Архитектурное бюро «AMG-project»','Москва, ул. Маршала Рыбалко, д. 2, корп. 6,  п. 3, оф. 139','+7 (495) 233-44-58','','','www.amgpro.ru',NULL,NULL,NULL,NULL,1,4),(5,'Юлия Петрова','ulia-petrova','.','После окончания факультета жилых и общественных зданий МАрхИ Юлия Петрова работала в «Моспроект-2» и частных архитектурных бюро, а в 2005 году открыла собственный архитектурный бизнес. «Интересоваться новыми тенденциями в архитектуре и искусстве и использовать эти знания в создании новых объектов» — так формулирует Юлия свой творческий девиз. Основное направление деятельности «Июль-студии» — жилые интерьеры.','/uploads/design_05-min1516015721.png','Архитектурное бюро  «ИЮЛЬ-СТУДИЯ»','','+7 (916) 687-11-22','','julystudio@mail.ru ','',NULL,NULL,NULL,NULL,1,5),(6,'Марина Рафальсон и  Виктория Нерсесьянц','marina-rafalson-i-viktoria-nersesanc','.','Компания «Вместе» существует уже 7 лет. Это союз трёх направлений в дизайне: мебели, текстиля и интерьера. Дизайнер Марина Рафальсон и архитектор Виктория Нерсесьянц ведут направление интерьера и работают в этой области уже почти 20 лет. Создавая новые пространства, они руководствуются принципом «комфорт, лёгкость и чистота линий».','/uploads/design_06-min1516020912.png','Компания «Вместе»','','+7 (925) 772-00-15','+7 (903) 961-77-06','mrafalson@mail.ru   |   x72x@yandex.ru','',NULL,NULL,NULL,NULL,1,6),(8,'Алексей Розенберг','aleksej-rozenberg','.','Кандидат архитектуры, член Московского архитектурного общества и Союза архитекторов России Алексей Розенберг ведет частную архитектурную практику с 1986 года. Своими любимыми направлениями в проектировании называет брутализм и риджионализм, то есть обращение к региональной тематике и традициям. Победитель, лауреат и номинант многочисленных российских и международных архитектурных премий. Мастерская специализируется на малоэтажном жилье, частных и общественных интерьерах.','/uploads/design_08-min1516022676.png','Мастерская Алексея Розенберга','','+7 (916) 610-42-29','','ar4229@gmail.com','sites.google.com/site/alexeyrozenberg',NULL,NULL,NULL,NULL,1,7),(9,'Петр Костелов','petr-kostelov','.','Выпускник Алма-Атинского театрально-художественного института и член Союза Архитекторов России Петр Костелов специализируется на интерьерах. «Максимально использовать возможности пространства с минимальными затратами» — творческое кредо, с которым он создает свои работы.','/uploads/design_09-min1516022933.png','Авторские работы','','','','pk71@ya.ru','www.kostelov.ru',NULL,NULL,NULL,NULL,1,8),(10,'Екатерина Кондратьева','ekaterina-kondrateva','','.','/uploads/design_10-min1516956069.png','','','','','','',NULL,NULL,NULL,NULL,NULL,9),(11,'Дмитрий Коршунов','dmitrij-korsunov','.','.','/uploads/design_111517123228.png','','','','','','',NULL,NULL,NULL,NULL,0,10),(12,'Евгения Фурменкова','evgenia-furmenkova','','.','/uploads/design_121517123506.png','','','','','','',NULL,NULL,NULL,NULL,NULL,11),(13,'при участии Дмитрия Соломонова','pri-ucastii-dmitria-solomonova','','.','/uploads/design_131517123736.png','','','','','','',NULL,NULL,NULL,NULL,NULL,12),(14,'Антон Фруктов','anton-fruktov','.','Основатели студии Антон и Марина Фруктовы, выпускники МГХПА им. С. Г. Строганова, входят в рейтинг 100 лучших дизайнеров и архитекторов России по версии редакции журнала Architectural Digest, являются членами Российской Ассоциации Декораторов и Дизайнеров Интерьера. Своё бюро «Дизайн в кубе | Design3» они создали в 2004 году. В 2019 году название сменилось на «FRUKTOV INTERIORS». За это время спроектировано и построено более 100 частных и общественных объектов в Москве и за рубежом. Девиз Фруктовых: «Мы бескомпромиссны. Но, к счастью, только в вопросах качества».','/uploads/design_141539968357.png','FRUKTOV INTERIORS','Москва, Причальный пр-д, 8к1','+7 (499) 647-40-01','','info@fruktovinteriors.com','www.fruktovinteriors.com',NULL,NULL,NULL,NULL,1,13),(15,'Марина Фруктова','marina-fruktova','.','Основатели студии Антон и Марина Фруктовы, выпускники МГХПА им. С. Г. Строганова, входят в рейтинг 100 лучших дизайнеров и архитекторов России по версии редакции журнала Architectural Digest, являются членами Российской Ассоциации Декораторов и Дизайнеров Интерьера. Своё бюро «Дизайн в кубе | Design3» они создали в 2004 году. В 2019 году название сменилось на «FRUKTOV INTERIORS». За это время спроектировано и построено более 100 частных и общественных объектов в Москве и за рубежом. Девиз Фруктовых: «Мы бескомпромиссны. Но, к счастью, только в вопросах качества».','/uploads/design_151539968370.png','FRUKTOV INTERIORS','Москва, Причальный пр-д, 8к1','+7 (499) 647-40-01','','info@fruktovinteriors.com','www.fruktovinteriors.com',NULL,NULL,NULL,NULL,1,14),(16,'Олеся Ситникова','olesa-sitnikova','.','Студия была основана Олесей Ситниковой в 2005 году. Философия студии дизайна интерьеров «Арх.Предмет» основана на принципах эффективного проектирования частных и общественных пространств. На всех этапах проектирования функциональность и экологичность уступает лишь эстетике и комфорту. По словам основательницы студии, «гармонично спроектированное пространство вокруг вас — это возможность зафиксировать уникальный этап вашего индивидуального прогресса».','/uploads/design_161540116892.png','Студия дизайна интерьеров и архитектуры «АРХ.ПРЕДМЕТ»','Москва, ул. Малая Дмитровка, 16','+7 (495) 984-87-02','','info@arch-predmet.com','www.arch-predmet.com',NULL,NULL,NULL,NULL,1,15),(17,'Татьяна Минина','tatana-minina','','Татьяна Минина','/uploads/design_171540116909.png','','','','','','',NULL,NULL,NULL,NULL,NULL,16),(18,'Сергей Попов','sergej-popov','. ','Руководитель мастерской «Архитектурное ателье», основанной в 1992 году. В настоящее время — практикующий архитектор. Основная специализация — загородные дома премиум класса. Каждый проект делается для конкретного человека с учетом его индивидуальных особенностей. Философия архитектора: смысл работы архитектора — в материализации архитектурного проекта в виде построенного здания, а не в создании пачки чертежей и картинок. Заказчик должен понимать, что создать идеальный проект невозможно. Можно потратить сколько угодно времени на изменение и исправление хорошего проекта. Лучше быть реалистом и прожить эти годы в своём новом доме.','/uploads/design_181541611227.png','Мастерская «Архитектурное ателье»','','','','aapop@yandex.ru','',NULL,NULL,NULL,NULL,1,17),(19,'Лев Шувалов','lev-suvalov','','Лев Шувалов','/uploads/design_191541671261.png','','','','','','',NULL,NULL,NULL,NULL,NULL,19),(20,'Наталья Ермакова','natala-ermakova','','Наталья Ермакова','/uploads/00001549961827.png','','','','','','',NULL,NULL,NULL,NULL,NULL,20),(21,'Павел Романов','pavel-romanov','. ','Павел Романов является главным архитектором и руководителем бюро «П.Ром», основанного в 2006 году. Коллектив бюро — это настоящая команда единомышленников, а командная работа — залог успеха бюро. Участие нескольких специалистов в разработке проекта позволяет найти оптимальное решение на всех стадиях проектирования. Многолетний опыт, обширные знания современных мировых тенденций позволяют коллективу мастерской успешно проектировать здания различного назначения, разрабатывать градостроительные предложения, создавать оригинальные интерьерные решения.','/uploads/001581093591.png','Архитектурное бюро Павла Романова «П.РОМ»','Москва, ул. Большая Полянка, 51А/9, оф. 417','+7 (495) 959-12-01','','levapasha@gmail.com','www.p-rom.com',NULL,NULL,NULL,NULL,1,21),(22,'Елена Дроботова','elena-drobotova','.','Мечтала работать дизайнером с детства. Окончила в 2006 году Технологический университет сервиса в городе Тольятти по специальности «Проектирование интерьеров и оборудования». Во время обучения в институте устроилась в архитектурную мастерскую, с тех пор работает по профессии и постоянно совершенствуется. Открыла собственное дизайн-бюро в 2015 году.','/uploads/001581415805.png','Drobotova Design','','+7 (926) 725-88-25','','drobotova.design@gmail.com','www.drobotovadesign.com',NULL,NULL,NULL,NULL,1,22),(23,'Александра Шувалова','aleksandra-suvalova','.','Окончила Московский архитектурный институт в 2008 году и с тех пор пробовала себя в различных направлениях: от градостроительства до проектирования спортивных объектов государственного значения. Последние восемь лет реализует интерьеры и индивидуальные дома класса люкс. Александра лично занимается всеми этапами проектирования: от походов с заказчиками по магазинам до выполнения 3D-графики. В результате получаются цельные, продуманные до мелочей проекты.','/uploads/design_20-min1590574214.png','Авторские работы','','+7 (926) 285-96-23','','atriputa@me.com','www.archinwork.com',NULL,NULL,NULL,NULL,1,24),(24,'Марина Толстая','marina-tolstaa','.','Работает в компании «Орбат» со дня её основания. Окончила Российский экономический университет им. Плеханова, по основному роду деятельности — экономист. В 2005 году окончила курсы при Московском архитектурном институте. Ведёт проекты по личной просьбе заказчиков, которые знают, что все их пожелания будут выполнены и объект сдан в срок.','/uploads/design_21-min1590574324.png','ЗАО «Орбат»','','+7 (910) 000-75-81','','zao-orbat@yandex.ru','www.orbat.ru',NULL,NULL,NULL,NULL,1,18);
