INSERT INTO `event` VALUES (1,'25 лет компании ОРБАТ',1496091600,'К своему 25-летию строительная компания «ОРБАТ» приурочила вручение премии за самые яркие достижения в области архитектуры. Ведущий торжества – Евгений Папунаишвили.','/uploads/new_01-min1516720266.jpg','25-let-kompanii-orbat','','','',''),(2,'Презентация книги ОРБАТ',1496091600,'«Интерьер от первого лица» – это сборник проектов, реализованных московскими архитекторами при участии компании «ОРБАТ». Издательство TATLIN, Екатеринбург. ','/uploads/new_02-min1516720212.jpg','prezentacia-knigi-orbat','','','',''),(3,'Объект «В гармонии с природой» сдан',1489093200,'Объект: дом в Николо-Урюпино\r\nОбщая площадь: 880 m2\r\nРеализация: 2017','/uploads/new_03-min1516720253.jpg','catalog/stroitelstvo/v-garmonii-s-prirodoj','','','',''),(4,'Выход второй книги «Интерьер от первого лица»',1584651600,'20 марта 2020 года строительная компания «Орбат» выпустила свою второю книгу. Издательство Tatlin, Екатеринбург. ','/uploads/new_04-min1591265715.jpg','vyhod-vtoroj-knigi-interer-ot-pervogo-lica','','','','');
/*!40000 ALTER TABLE `event` ENABLE KEYS */;
UNLOCK TABLES;

