INSERT INTO `partner` VALUES (1,'МБТМ','mbtm','/uploads/p11515771761.png','www.mbtm.ru','www.mebelclub.ru','Мебель, светильники, кухни, двери, перегородки, сантехника, аксессуары и предметы декора от лучших европейских и североамериканских производителей.',NULL,NULL,NULL,NULL),(2,'Холдинг «Макслевел»','holding-makslevel','/uploads/p21515771905.png','www.maxlevel.ru ','','Крупнейшая розничная сеть салонов по продаже сантехники, жилой и кухонной мебели, керамической плитки. 22 года успешной работы. Более 150 ведущих европейских брендов. 17 розничных салонов. Более 15 000 кв. м. экспозиции.',NULL,NULL,NULL,NULL),(3,'Villeroy & Boch','villeroy-boch','/uploads/p31515771933.png','www.villeroy-boch.ru ','','Мировой лидер в производстве сантехники, мебели \r\nдля ванных комнат, керамической плитки, столовой посуды и др. Комфорт, передовые стандарты качества, новейшие технологии — кредо Villeroy&Boch.',NULL,NULL,NULL,NULL),(4,'ОВК Комплекс','ovk-kompleks','/uploads/p41515773152.png','www.ovk-complex.ru  ','','Проектирование и подбор составных элементов систем энергоснабжения, вентиляции, кондиционирования, отопления, канализации и водоснабжения. Монтаж оборудования, настройка и обслуживание после установки.',NULL,NULL,NULL,NULL),(5,'Mobile Line Decore','mobile-line-decore','/uploads/p51515773192.png','www.m-ld.ru  ','','Полная комплектация интерьера. \r\nЗаказ мебели мировых брендов по каталогам. Текстиль. Собственное производство.',NULL,NULL,NULL,NULL),(6,'Окна Формат','okna-format','/uploads/p61515773244.png','www.oknaformat.ru  ','','Производство, реализация и монтаж деревянных и алюминиевых ограждающих конструкций различной конфигурации и сложности.',NULL,NULL,NULL,NULL),(7,'Магазин «Предметы»','magazin-predmety','/uploads/p71515773302.png','www.predmety-shop.ru   ','','Студия декора и шоу-рум эксклюзивных брендов: LISSOY, ARTISAN HOUSE, TAKAYAKA, DUWEL, GUAXS, Vanessa Mitrani, SKLO, Meier, Jacques Pergay.',NULL,NULL,NULL,NULL),(8,'Mediasector','mediasector','/uploads/p81515773354.png','www.mediasector.ru','','Современные слаботочные системы. \r\nБесшовный WiFi. Автоматизация. Полный цикл — \r\nот проектирования до обслуживания.',NULL,NULL,NULL,NULL),(9,'ESSE','esse','/uploads/p91515773414.png','www.parcet-esse.ru  ','','Напольные покрытия и деревянные 3D стеновые панели. Собственное производство. Неизменно высокое качество. Индивидуальный подход.',NULL,NULL,NULL,NULL),(10,'Дом Краски','dom-kraski','/uploads/p101515773475.png','www.domkraski.ru','','Разработка эксклюзивных декоративных покрытий, индивидуальный подбор уникальных систем защиты \r\nи окраски поверхностей профессиональными лакокрасочными материалами от ведущих \r\nевропейских производителей.',NULL,NULL,NULL,NULL),(11,'Exclusive Wood Group','exclusive-wood-group','/uploads/part_011590581349.png','www.oknaewg.ru','','Exclusive Wood Group объединила команду специалистов высокой квалификации для того, чтобы осуществить Ваши самые смелые идеи. Проектируем и изготавливаем деревянные окна, входные двери, зимние сады, фасадные системы исключительного дизайна по индивидуальным заказам.',NULL,NULL,NULL,NULL),(12,'Benjamin Moore','benjamin-moore','/uploads/part_021590581465.png','www.benjaminmoore.ru','','С 1995 года наша Компания является официальным дистрибьютором Benjamin Moore & Co. в Российской Федерации. Наши филиалы также работают в Казахстане и Беларуси. Фирменные покрытия Benjamin Moore по праву заняли ведущие позиции на российском рынке среди красок премиального сегмента.',NULL,NULL,NULL,NULL),(13,'Феникс','feniks','/uploads/part_031590581597.png','www.fenix-kamen.ru','','Компания «Феникс» предлагает широкий выбор натурального камня — мрамора, гранита, травертина и других — а также изделий из него. Постоянно в наличии более трёхсот наименований натурального камня различных цветов и размеров. Компания осуществляет продажу и монтаж как готовых элементов, так и изготавливает их на заказ.',NULL,NULL,NULL,NULL),(14,'Skorovarov','skorovarov','/uploads/part_041590581787.png','+7 (916) 800-00-02','','Изготовление уникальных элементов интерьера, мебели и светильников по индивидуальным заказам. Работа с металлом, деревом, стеклом. Собственное производство в Москве. Более 80 успешно выполненных заказов.',NULL,NULL,NULL,NULL);
/*!40000 ALTER TABLE `partner` ENABLE KEYS */;
UNLOCK TABLES;

