/*!40000 ALTER TABLE `review` DISABLE KEYS */;
INSERT INTO `review` VALUES (1,'Алексей Розенберг','Придуманный и разработанный проект нуждается в правильном воплощении и важная часть реализации — это «ручное прикосновение», то есть кропотливая ремесленная работа над каждой деталью, поверхностью, наполнением. Именно тогда объект приобретает качество художественности. Андрей Толстой готов к такой, затратной по времени и усилиям, работе и так же ориентирует своих сотрудников. В результате они становятся соавторами возникающего образа, поэтому я с удовольствием сотрудничаю с ними.','/uploads/06_ot-min1516719401.png','dmitrij-bykov',NULL,NULL,NULL,NULL),(3,'Марина Рафальсон','Случается в работе удача. Удача, когда не только результат, но и процесс работы над объектом доставляет огромное удовольствие. Наверное, в идеале так должно быть всегда, но чудо, что это вообще случается. Для меня этот счастливый случай выпал, когда партнером на объекте была строительная компания «Орбат» Андрея Толстого. От замысла до воплощения все шло на одном дыхании. Ставка делалась на безупречное качество и использование индивидуальных, специально спроектированных деталей интерьера. Строители выполнили все сложные задания: монтаж скрытых механизмов для огромных раздвижных дверей, съёмных деревянных панелей и потолков, скрывающих инженерные коммуникации.','/uploads/05_ot-min1516719428.png','marina-rafalson',NULL,NULL,NULL,NULL),(2,'Вера Герасимова','Строительная компания «Орбат» — это высокий профессионализм сотрудников, беспрецедентное качество выполнения работ и 100 % уверенность в результате.','/uploads/07_ot-min1516719448.png','irina-mavrodieva',NULL,NULL,NULL,NULL),(4,'Жанна Кочурова','С Андреем Толстым и его компанией я работаю с 96-го года — уже больше двадцати лет. Он только начинал во время нашего знакомства, и я тоже — только начинала. Он строил компанию на моих глазах и работал тогда сутками — в выходные, в праздники — не важно. Он очень трудолюбивый человек, но главное, он всегда готов поддержать тебя, взять на себя ответственность, подсказать нужный вариант технического решения. Благодаря этим качествам ему доверяют, в том числе и заказчики. Ему удалось создать уникальную команду, потому что он умеет правильно руководить людьми. Но все-таки его компания — это, прежде всего, он сам.','/uploads/04_ot-min1516719474.png','zanna-kocurova',NULL,NULL,NULL,NULL),(5,'Юлия Петрова','Для меня работа с Андреем Толстым и его командой — это заведомо положительный результат. Я знаю, что если строителями на объекте будет компания «Орбат», то я могу использовать в проекте любые технически сложные и нестандартные решения, и все будет выполнено идеально. Вероятно, поэтому объекты, построенные с Толстым, как правило, попадают на страницы журналов. Почти все мои объекты, которыми я могу гордиться, построены при участии Толстого. С Андреем мы знакомы больше 15 лет. Мы встретились с ним на одном из первых моих самостоятельных проектов, в то время я почти не имела опыта в реализации интерьеров, и мне была очень важна та постоянная поддержка, которую я ощущала со стороны более опытного Андрея и его команды. В процессе работы с ним не возникает обычных трений между архитектором и строителем, потому что все участники процесса заинтересованы в достижении качественного результата.','/uploads/03_ot-min1516719500.png','ulia-petrova',NULL,NULL,NULL,NULL),(6,'Ирина Мавродиева','Работа над большим объектом требует ежеминутного решения самых разнообразных задач, из которых художественные составляют лишь небольшую часть. Однако именно они влияют на конечный результат максимальным образом, и, чтобы иметь возможность сосредоточиться на них, важно иметь таких партнеров, которые разделяют с тобой бремя этой ноши, работают как единомышленники. Таким партнером для архитекторов является Андрей Толстой. Главное для него — это командная работа и ее качественный результат. Услуги «Орбат» не дешевы, но именно благодаря этому у компании есть ресурс, позволяющий ей сделать всегда непростой процесс строительства максимально комфортным для заказчика и уложиться в обозначенные сроки. У Толстого есть чутье на людей и правильный подход ко всем участникам и заинтересованным сторонам — своим сотрудникам, архитекторам, заказчикам. А итогом всегда становится счастливое переселение заказчиков в новый дом.','/uploads/02_ot-min1516719523.png','irina-mavrodieva',NULL,NULL,NULL,NULL),(7,'Дмитрий Быков','С Андреем Толстым и его компанией «Орбат» мы не расстаемся уже 21 год. Все это время мы работаем двумя партнерскими компаниями и как два товарища. Ценность Андрея и его сотрудников не только в профессионализме, но и в стремлении добиться лучшего результата на каждом объекте. Толстой же как личность, трудоголик и перфекционист, среди своих сотрудников имеет непререкаемый авторитет и, наверное, поэтому в его команде практически нет «текучки кадров». С заказчиками Андрей выстраивает отношения, исходя из принципа «снять максимум проблем». В общем, за все эти двадцать с лишним лет мы вместе построили много интересных, комфортных и надежных объектов.','/uploads/01_ot-min1516719555.png','dmitrij-bykov',NULL,NULL,NULL,NULL);
/*!40000 ALTER TABLE `review` ENABLE KEYS */;
