INSERT INTO `video` VALUES (1,'25 лет профессионализма','7vfInRfyo1s','В видеоролике ниже генеральный директор компании «ОРБАТ» Андрей Толстой и прораб Вадим Степаненко подробно рассказывают о тонкостях ремонта, а также раскрывают некоторые особенности работы.','25-let-professionalizma',NULL,NULL,NULL,NULL,0,0),(2,'Дом на болотистой почве','Z6_-Y1IxL1M','Особенности капитального строительства компании «ОРБАТ» на примере Дома на болотистой почве. Уникальные методы строительства.  ','28-let-professionalizma',NULL,NULL,NULL,NULL,0,0),(3,'Квартира в стиле арт-деко','AYz6m405iy8','Генеральный директор компании «ОРБАТ» Андрей Толстой расскажет о тонкостях ремонта и важных нюансах в реализации проекта в стиле арт-деко.','kvartira-v-stile-art-deko',NULL,NULL,NULL,NULL,0,0),(4,'Обзор проекта от Андрея Толстого','ctsz8a0qvAA','Финальная стадия завершения – подробный обзор придомовой территории и внутреннего убранства. Реконструкция дома и сложные ландшафтные работы от компании «ОРБАТ».','obzor-proekta-ot-andrea-tolstogo',NULL,NULL,NULL,NULL,0,0),(5,'Обзор дома на болотистой почве','VAfnooPAjLE','Обзор завершенного в 2018 году проекта. Строительство на болотистой местности, множество необычных и сложных решений во внутренней отделке дома, панорама уникального ландшафта территории.','obzor-doma-na-bolotistoj-pocve',NULL,NULL,NULL,NULL,0,0),(6,'Дом в Пирогово','h6kDFpaSjhY','Обзор стадии завершения проекта дома в Пирогово в лесу. Архитектор – Алексей Розенберг. Особенности капитального строительства.','dom-v-pirogovo',NULL,NULL,NULL,NULL,0,0),(7,'Воскресное утро в офисе','uFMNmqzpeZo','Большой обзор завершенного объекта – офиса. Проект Сергея Колчина.','voskresnoe-utro-v-ofise',NULL,NULL,NULL,NULL,1,0),(8,'Квартира в традиционном стиле','PlLobDZ8_KE','Обзор квартиры на Спортивной в традиционном стиле с элементами Арт-деко. Андрей Толстой и архитектор Жанна Кочурова подробно рассказывают про особенности реализации. Классический традиционный Московский объект. ','kvartira-v-tradicionnom-stile',NULL,NULL,NULL,NULL,1,0),(9,'Квартира в Замоскворечье','ZfFttg2TdcA','Квартира в Замоскворечье площадью 124 кв.м. Проект архитектора Веры Герасимовой. Большой обзор.','kvartira-v-zamoskvorece',NULL,NULL,NULL,NULL,1,0),(10,'Современный дом в архитектуре Новой Англии','v1IXTILCLwY','Обзор завершенного проекта в старом подмосковном дачном поселке. Загородный дом в архитектуре Новой Англии. Проект московского архитектора Дмитрия Быкова.','sovremennyj-dom-v-arhitekture-novoj-anglii',NULL,NULL,NULL,NULL,1,0),(11,'Интерьер загородного дома','n-ecFwJVbss?si=CrFWUGFNOZ7ff2p8','Обзор интерьера загородного дома. Профилактика электронных, электрических и сантехнических приборов. Съемка интерьеров для глянцевых журналов. Автор проекта – архитектор Юлия Петрова. При участии архитектора Дмитрия Быкова.','interer-zagorodnogo-doma-proekt-2023-goda',NULL,NULL,NULL,NULL,1,0),(12,'Последний проект архитектора Алексея Розенберга.','ID0tOALO8go','Обзор загородного дома, интерьеров, придомовых территорий.','poslednij-proekt-arhitektora-aleksea-rozenberga',NULL,NULL,NULL,NULL,1,0),(13,'Обзор сада и огорода на болоте.','BCmfAd_ISSQ','Сентябрь, время собирать урожай. Обзор сада и огорода на болоте. Хозяйственный блок и погреб. ','obzor-sada-i-ogoroda-na-bolote',NULL,NULL,NULL,NULL,1,0);
